from typing import List
from collections import defaultdict

def solve(n: int, edges: List[List[int]], label: str) -> int:
    # Build the adjacency list
    graph = defaultdict(list)
    for u, v in edges:
        graph[u].append(v)
        graph[v].append(u)

    # Function to check if a path is a palindrome
    def is_palindrome(path: List[int]) -> bool:
        return label[path[0]] == label[path[-1]] and all(label[path[i]] == label[path[-i-1]] for i in range(len(path)//2))

    # DFS to find the longest palindrome path
    def dfs(node: int, visited: set, path: List[int]) -> int:
        if node in visited:
            return 0
        visited.add(node)
        path.append(node)
        max_len = 1  # At least one node is a palindrome of length 1
        for neighbor in graph[node]:
            if neighbor not in visited:
                current_len = dfs(neighbor, visited, path)
                if current_len > 0:
                    if is_palindrome(path):
                        max_len = max(max_len, len(path))
                    path.pop()
        visited.remove(node)
        return max_len

    max_palindrome_length = 0
    for start in range(n):
        visited = set()
        path = []
        current_len = dfs(start, visited, path)
        max_palindrome_length = max(max_palindrome_length, current_len)

    return max_palindrome_length
